# Windmill Script: Get ServiceNow Incident/Case Summary (Production Instance)
#
# Supports:
# - INCxxxxxxxx incidents (incident table)
# - CSxxxxxxxx customer service cases (sn_customerservice_case / csm_case)

import base64
import logging
import os
import re
import threading
from datetime import datetime
from typing import Dict, Optional, Any, List, Tuple

import requests

logging.basicConfig(
    level=logging.INFO,
    format="%(levelname)s: %(message)s",
    force=True
)
logger = logging.getLogger(__name__)


# ============================================================================
# ServiceNow Library Code (Inlined)
