def get_windmill_variable(
    variable_name: str,
    default: Optional[str] = None,
    username: Optional[str] = None,
    required: bool = False
) -> Optional[str]:
    """
    Get a variable from Windmill using triple access pattern:
    1. Try wmill.get_variable()
    2. Try os.getenv()
    3. Fall back to Windmill API if wmill import is unavailable
    """
    # 1) wmill.get_variable()
    try:
        import wmill

        if username:
            try:
                value = wmill.get_variable(f"u/{username}/{variable_name}")
                if value:
                    logger.info(f"Found {variable_name} via wmill.get_variable() at u/{username}/{variable_name}")
                    return value.strip() if isinstance(value, str) else value
            except Exception:
                pass

        script_path = os.getenv("WM_SCRIPT_PATH", "")
        if "/u/" in script_path:
            parts = script_path.split("/u/")
            if len(parts) > 1:
                api_username = parts[1].split("/")[0]
                try:
                    value = wmill.get_variable(f"u/{api_username}/{variable_name}")
                    if value:
                        logger.info(f"Found {variable_name} via wmill.get_variable() at u/{api_username}/{variable_name}")
                        return value.strip() if isinstance(value, str) else value
                except Exception:
                    pass

        # fallback user path
        try:
            value = wmill.get_variable(f"u/bspilker/{variable_name}")
            if value:
                logger.info(f"Found {variable_name} via wmill.get_variable() at u/bspilker/{variable_name}")
                return value.strip() if isinstance(value, str) else value
        except Exception:
            pass

    except ImportError:
        logger.debug("wmill import not available")
    except Exception as e:
        logger.debug(f"wmill.get_variable() failed: {e}")

    # 2) os.getenv()
    value = os.getenv(variable_name)
    if value:
        logger.info(f"Found {variable_name} via os.getenv()")
        return value.strip() if isinstance(value, str) else value

    # 3) Windmill API fallback only if wmill import isn't available
    wm_token = None
    base_url = None
    workspace = None

    wmill_available = False
    try:
        import wmill  # noqa: F401
        wmill_available = True
    except ImportError:
        pass

    if not wmill_available:
        wm_token = os.getenv("WM_TOKEN")
        base_url = os.getenv("WM_BASE_URL") or os.getenv("BASE_INTERNAL_URL")
        workspace = os.getenv("WM_WORKSPACE")

        if wm_token and base_url and workspace:
            try:
                api_username = username or os.getenv("WM_USERNAME")
                if not api_username:
                    script_path = os.getenv("WM_SCRIPT_PATH", "")
                    if "/u/" in script_path:
                        parts = script_path.split("/u/")
                        if len(parts) > 1:
                            api_username = parts[1].split("/")[0]
                if not api_username:
                    api_username = "bspilker"

                api_url = (
                    f"{base_url.rstrip('/')}/api/w/{workspace}/variables/get_value/"
                    f"u/{api_username}/{variable_name}"
                )
                response = requests.get(
                    api_url,
                    headers={"Authorization": f"Bearer {wm_token}"},
                    timeout=10
                )
                if response.status_code == 200:
                    api_value = response.json()
                    if isinstance(api_value, str):
                        api_value = api_value.strip()
                    logger.info(f"Found {variable_name} via Windmill API")
                    return api_value
            except Exception:
                pass

    if required:
        error_msg = (
            f"{variable_name} is required but not found.\n"
            f"Tried:\n"
            f"  1. wmill.get_variable()\n"
            f"  2. Environment variable: {variable_name}\n"
            f"\nPlease set {variable_name} as:\n"
            f"  - Windmill variable at u/bspilker/{variable_name}\n"
        )
        raise ValueError(error_msg)

    return default


class ServiceNowConfig:
    """Configuration for ServiceNow API access."""

    def __init__(self, username: Optional[str] = None):
        self.instance_url = "https://presidio.service-now.com".rstrip("/")
        self.api_url = f"{self.instance_url}/api/now"
        self.timeout = 30

        self.auth_type = "api_key"

        logger.info("Attempting to fetch SNC_AUTH from u/bspilker/SNC_AUTH")
        self.api_key = get_windmill_variable("SNC_AUTH", username=username)

        if not self.api_key:
            logger.info("SNC_AUTH not found, trying SERVICENOW_API_KEY")
            self.api_key = get_windmill_variable("SERVICENOW_API_KEY", username=username)

        if self.api_key:
            logger.info("API key successfully loaded from variable")
        else:
            logger.warning("No API key found - authentication will fail")

        self.api_key_header = "Authorization"
        self.api_key_prefix = "Basic"

        self.username = None
        self.password = None
        self.oauth_client_id = None
        self.oauth_client_secret = None
        self.oauth_username = None
        self.oauth_password = None
        self.oauth_token_url = None
        self._oauth_token: Optional[str] = None
        self._oauth_token_type: Optional[str] = None


def get_auth_headers(config: ServiceNowConfig) -> Dict[str, str]:
    headers = {
        "Accept": "application/json",
        "Content-Type": "application/json",
    }

    if config.auth_type == "api_key":
        if not config.api_key:
            raise ValueError(
                "API key is required. Set u/bspilker/SNC_AUTH (secret), "
                "SERVICENOW_API_KEY, or SNC_AUTH."
            )
        api_key_value = config.api_key
        if config.api_key_prefix:
            api_key_value = f"{config.api_key_prefix} {api_key_value}"
        headers[config.api_key_header] = api_key_value

    elif config.auth_type == "basic":
        if not config.username or not config.password:
            raise ValueError("SERVICENOW_USERNAME and SERVICENOW_PASSWORD are required for basic auth")
        auth_str = f"{config.username}:{config.password}"
        encoded = base64.b64encode(auth_str.encode()).decode()
        headers["Authorization"] = f"Basic {encoded}"

    elif config.auth_type == "oauth":
        if not config._oauth_token:
            _get_oauth_token(config)
        if config._oauth_token:
            headers["Authorization"] = f"{config._oauth_token_type} {config._oauth_token}"
        else:
            raise ValueError("Failed to obtain OAuth token")

    else:
        raise ValueError(f"Unsupported authentication type: {config.auth_type}")

    return headers


def _get_oauth_token(config: ServiceNowConfig):
    if not config.oauth_client_id or not config.oauth_client_secret:
        raise ValueError("SERVICENOW_CLIENT_ID and SERVICENOW_CLIENT_SECRET are required for OAuth")

    token_url = config.oauth_token_url
    if not token_url:
        instance_parts = config.instance_url.split(".")
        if len(instance_parts) < 2:
            raise ValueError(f"Invalid instance URL: {config.instance_url}")
        instance_name = instance_parts[0].split("//")[-1]
        token_url = f"https://{instance_name}.service-now.com/oauth_token.do"

    auth_str = f"{config.oauth_client_id}:{config.oauth_client_secret}"
    auth_header = base64.b64encode(auth_str.encode()).decode()
    headers = {
        "Authorization": f"Basic {auth_header}",
        "Content-Type": "application/x-www-form-urlencoded"
    }

    logger.info("Attempting OAuth client_credentials grant...")
    response = requests.post(token_url, headers=headers, data={"grant_type": "client_credentials"})
    if response.status_code == 200:
        token_data = response.json()
        config._oauth_token = token_data.get("access_token")
        config._oauth_token_type = token_data.get("token_type", "Bearer")
        return

    if config.oauth_username and config.oauth_password:
        logger.info("Attempting OAuth password grant...")
        response = requests.post(
            token_url,
            headers=headers,
            data={
                "grant_type": "password",
                "username": config.oauth_username,
                "password": config.oauth_password
            }
        )
        if response.status_code == 200:
            token_data = response.json()
            config._oauth_token = token_data.get("access_token")
            config._oauth_token_type = token_data.get("token_type", "Bearer")
            return

    raise ValueError("Failed to get OAuth token")


def make_servicenow_request(
    config: ServiceNowConfig,
    method: str,
    endpoint: str,
    params: Optional[Dict[str, Any]] = None,
    json_data: Optional[Dict[str, Any]] = None,
    suppress_403: bool = False,
) -> Dict[str, Any]:
    url = f"{config.api_url}{endpoint}"
    headers = get_auth_headers(config)

    try:
        response = requests.request(
            method=method.upper(),
            url=url,
            headers=headers,
            params=params,
            json=json_data,
            timeout=config.timeout,
        )
        response.raise_for_status()
        return response.json()

    except requests.exceptions.HTTPError as e:
        if suppress_403 and getattr(e, "response", None) is not None and e.response.status_code == 403:
            return {"result": []}
        logger.error(f"ServiceNow API request failed: {e}")
        if getattr(e, "response", None) is not None:
            logger.error(f"Response body: {e.response.text}")
        raise

    except requests.exceptions.RequestException as e:
        logger.error(f"ServiceNow API request failed: {e}")
        if getattr(e, "response", None) is not None:
            logger.error(f"Response body: {e.response.text}")
        raise


def load_config(username: Optional[str] = None) -> ServiceNowConfig:
    return ServiceNowConfig(username=username)


# ============================================================================
# Helper Functions
# ============================================================================

def parse_journal_field_text(text: str, entry_type: str) -> List[Dict]:
    if not text or not text.strip():
        return []

    entries = []
    lines = text.split("\n")
    current_entry = None

    for line in lines:
        line = line.strip()
        if not line:
            if current_entry:
                entries.append(current_entry)
                current_entry = None
            continue

        if len(line) > 19 and line[2] == "-" and line[5] == "-" and line[10] == " ":
            try:
                timestamp_str = line[:19]
                author_part = line[22:] if len(line) > 22 else ""
                author = author_part.split("(")[0].strip() if "(" in author_part else author_part.strip()

                if current_entry:
                    entries.append(current_entry)

                current_entry = {
                    "timestamp": timestamp_str,
                    "type": entry_type,
                    "author": author or "Unknown",
                    "content": "",
                }
            except Exception:
                if current_entry:
                    current_entry["content"] += "\n" + line if current_entry["content"] else line
        else:
            if current_entry:
                current_entry["content"] += "\n" + line if current_entry["content"] else line
            else:
                current_entry = {
                    "timestamp": "",
                    "type": entry_type,
                    "author": "Unknown",
                    "content": line,
                }

    if current_entry:
        entries.append(current_entry)

    return entries


def _generate_timeline_summary(
    timeline_events: List[Dict[str, Any]],
    incident_data: Dict[str, Any]
) -> Dict[str, Any]:
    state_map = {
        "1": "New", "2": "In Progress", "3": "On Hold",
        "4": "Resolved", "5": "Closed", "6": "Cancelled",
        "7": "Pending", "8": "Awaiting Information",
    }

    if not timeline_events:
        return {
            "summary_text": "No activity recorded yet. This is a new record.",
            "key_events": [],
            "recent_activity": [],
            "state_changes": [],
            "statistics": {
                "total_events": 0,
                "comments": 0,
                "work_notes": 0,
                "state_changes": 0,
            },
        }

    state_changes = [e for e in timeline_events if e.get("type") == "state_change"]
    comments = [e for e in timeline_events if e.get("type") == "comment"]
    work_notes = [e for e in timeline_events if e.get("type") == "work_note"]

    summary_parts = []
    created_on = incident_data.get("sys_created_on", "")
    if created_on:
        summary_parts.append(f"Record created on {created_on}")

    if state_changes:
        summary_parts.append(f"State changes: {len(state_changes)} total")

    total_activity = len(comments) + len(work_notes)
    if total_activity > 0:
        summary_parts.append(f"Activity: {len(comments)} comment(s), {len(work_notes)} work note(s)")

    recent_activity = timeline_events[-5:] if len(timeline_events) > 5 else timeline_events
    recent_summary = []
    for event in recent_activity:
        event_type = event.get("type", "")
        timestamp = event.get("timestamp", "")
        author = event.get("author") or event.get("user", "Unknown")

        if event_type == "comment":
            content_preview = event.get("content", "")[:100]
            recent_summary.append(f"{timestamp}: Comment by {author}: {content_preview}...")
        elif event_type == "work_note":
            content_preview = event.get("content", "")[:100]
            recent_summary.append(f"{timestamp}: Work note by {author}: {content_preview}...")
        elif event_type == "state_change":
            old_val = event.get("old_value", "")
            new_val = event.get("new_value", "")
            old_text = state_map.get(old_val, old_val)
            new_text = state_map.get(new_val, new_val)
            recent_summary.append(f"{timestamp}: State changed from '{old_text}' to '{new_text}' by {author}")

    summary_text = "\n".join(summary_parts) if summary_parts else "No timeline activity recorded."

    return {
        "summary_text": summary_text,
        "key_events": [],
        "recent_activity": recent_summary,
        "state_changes": [
            {
                "timestamp": e.get("timestamp", ""),
                "from": state_map.get(e.get("old_value", ""), e.get("old_value", "")),
                "to": state_map.get(e.get("new_value", ""), e.get("new_value", "")),
                "by": e.get("user", "Unknown"),
            }
            for e in state_changes
        ],
        "statistics": {
            "total_events": len(timeline_events),
            "comments": len(comments),
            "work_notes": len(work_notes),
            "state_changes": len(state_changes),
        },
    }


def _normalize_record_number(record_number: str) -> str:
    return (record_number or "").strip().upper()


def _get_table_candidates(record_number: str) -> List[Tuple[str, str]]:
    rn = _normalize_record_number(record_number)

    if rn.startswith("INC"):
        return [("incident", "incident")]

    if rn.startswith("CS"):
        return [
            ("sn_customerservice_case", "case"),
            ("csm_case", "case"),
        ]

    return [
        ("incident", "incident"),
        ("sn_customerservice_case", "case"),
        ("csm_case", "case"),
        ("task", "task"),
    ]


def _lookup_record_by_number(
    config: ServiceNowConfig,
    record_number: str
) -> Tuple[Optional[str], Optional[str], Optional[Dict[str, Any]]]:
    query_params = {
        "sysparm_query": f"number={record_number}",
        "sysparm_limit": 1,
        "sysparm_display_value": "true",
        "sysparm_exclude_reference_link": "true",
    }

    for table_name, record_type in _get_table_candidates(record_number):
        try:
            response = make_servicenow_request(
                config=config,
                method="GET",
                endpoint=f"/table/{table_name}",
                params=query_params,
            )
            rows = response.get("result", [])
            if rows:
                logger.info(f"Found {record_number} in table '{table_name}'")
                return table_name, record_type, rows[0]
        except requests.exceptions.HTTPError as e:
            status = e.response.status_code if getattr(e, "response", None) else None
            if status in (400, 403, 404):
                logger.info(f"Table '{table_name}' unavailable or inaccessible (HTTP {status}); trying next")
                continue
            raise

    return None, None, None


def _extract_inc_numbers_from_obj(value: Any) -> List[str]:
    """Recursively extract INC numbers from nested dict/list/string values."""
    pattern = re.compile(r"\bINC\d{7,}\b", re.IGNORECASE)
    found: List[str] = []

    def _add(text: str):
        for match in pattern.findall(text or ""):
            inc = match.upper()
            if inc not in found:
                found.append(inc)

    def _walk(obj: Any):
        if obj is None:
            return
        if isinstance(obj, str):
            _add(obj)
            return
        if isinstance(obj, dict):
            for v in obj.values():
                _walk(v)
            return
        if isinstance(obj, list):
            for item in obj:
                _walk(item)

    _walk(value)
    return found


def _find_related_incidents_for_case(
    config: ServiceNowConfig,
    case_sys_id: str,
    case_number: str,
    case_record: Optional[Dict[str, Any]] = None,
)

-> List[str]:
    """
    Best-effort lookup for incidents related to a CS case.

    Strategy:
    1) Parse INC numbers directly from the case record payload.
    2) Query task_rel_task for parent/child links and parse INC numbers.
    3) Query incident table for parent=case_sys_id or correlation_id=case_number.
    4) Query incident text fields containing the case number.
    """
    related: List[str] = []

    def add_many(items: List[str]):
        for inc in items:
            up = inc.upper()
            if up.startswith("INC") and up not in related:
                related.append(up)

    if case_record:
        add_many(_extract_inc_numbers_from_obj(case_record))

    # task_rel_task parent/child linkage
    try:
        rel_params = {
            "sysparm_query": f"parent={case_sys_id}^ORchild={case_sys_id}",
            "sysparm_limit": 50,
            "sysparm_display_value": "true",
            "sysparm_exclude_reference_link": "true",
        }
        rel_resp = make_servicenow_request(
            config=config,
            method="GET",
            endpoint="/table/task_rel_task",
            params=rel_params,
        )
        for row in rel_resp.get("result", []):
            add_many(_extract_inc_numbers_from_obj(row))
    except Exception as e:
        logger.debug(f"task_rel_task lookup skipped/failed: {e}")

    # incidents directly linked via parent or correlation_id
    try:
        direct_params = {
            "sysparm_query": f"parent={case_sys_id}^ORcorrelation_id={case_number}",
            "sysparm_limit": 20,
            "sysparm_display_value": "true",
            "sysparm_exclude_reference_link": "true",
            "sysparm_fields": "number,parent,correlation_id,short_description,description",
        }
        direct_resp = make_servicenow_request(
            config=config,
            method="GET",
            endpoint="/table/incident",
            params=direct_params,
        )
        for row in direct_resp.get("result", []):
            num = (row.get("number") or "").strip().upper()
            if num.startswith("INC") and num not in related:
                related.append(num)
            add_many(_extract_inc_numbers_from_obj(row))
    except Exception as e:
        logger.debug(f"direct incident relation lookup skipped/failed: {e}")

    # incidents mentioning the case number in text
    try:
        text_params = {
            "sysparm_query": f"short_descriptionLIKE{case_number}^ORdescriptionLIKE{case_number}",
            "sysparm_limit": 10,
            "sysparm_display_value": "true",
            "sysparm_exclude_reference_link": "true",
            "sysparm_fields": "number,short_description,description",
        }
        text_resp = make_servicenow_request(
            config=config,
            method="GET",
            endpoint="/table/incident",
            params=text_params,
        )
        for row in text_resp.get("result", []):
            num = (row.get("number") or "").strip().upper()
            if num.startswith("INC") and num not in related:
                related.append(num)
    except Exception as e:
        logger.debug(f"text relation lookup skipped/failed: {e}")

    return related


def _resolve_input_number(
    incident_number: Optional[str],
    case_number: Optional[str],
) -> Tuple[Optional[str], Optional[str], Optional[str]]:
    """
    Resolve which input to use and validate prefix.

    Returns:
        (record_number, input_label, error_message)
    """
    inc = _normalize_record_number(incident_number) if incident_number else ""
    cs = _normalize_record_number(case_number) if case_number else ""

    if inc and cs and inc != cs:
        return None, None, "Provide only one input: incident_number or case_number"

    record_number = inc or cs
    if not record_number:
        return None, None, "incident_number or case_number is required"

    if record_number.startswith("INC"):
        return record_number, "incident_number", None
    if record_number.startswith("CS"):
        return record_number, "case_number", None

    return None, None, "Record number must start with INC or CS"


# ============================================================================
# Main Script Logic
# ============================================================================

def main(
    incident_number: Optional[str] = None,
    case_number: Optional[str] = None,
) -> Dict[str, Any]:
    """
    Get a ServiceNow record by number and return a formatted summary.

    Args:
        incident_number: ServiceNow incident number (INC...)
        case_number: ServiceNow case number (CS...)
    """
    try:
        record_number, input_label, input_error = _resolve_input_number(
            incident_number=incident_number,
            case_number=case_number,
        )
        if input_error:
            return {
                "success": False,
                "message": input_error,
                "incident": None,
            }

        logger.info("Fetching results, please wait...")

        script_path = os.getenv("WM_SCRIPT_PATH", "")
        username = None
        if "/u/" in script_path:
            parts = script_path.split("/u/")
            if len(parts) > 1:
                username = parts[1].split("/")[0]
                logger.info(f"Auto-detected username from script path: {username}")

        config = load_config(username=username)

        table_name, record_type, incident_data = _lookup_record_by_number(config, record_number)

        if not incident_data:
            response = {
                "success": False,
                "message": f"Record {record_number} not found",
                "incident": None,
            }
            if input_label:
                response[input_label] = record_number
            return response

        incident_sys_id = incident_data.get("sys_id")
        number_from_query = (incident_data.get("number") or "").strip().upper()

        if number_from_query != record_number:
            logger.warning(f"Record mismatch requested={record_number} got={number_from_query}")
            response = {
                "success": False,
                "message": f"Record mismatch: requested {record_number} but got {number_from_query}",
                "incident": None,
            }
            if input_label:
                response[input_label] = record_number
            return response

        if not incident_sys_id:
            response = {
                "success": False,
                "message": "Could not get record sys_id",
                "incident": None,
            }
            if input_label:
                response[input_label] = record_number
            return response

        logger.info(f"Fetching journal data for {record_number} from {table_name} (sys_id: {incident_sys_id})")

        # Verify sys_id maps to the same record number
        try:
            verify_params = {
                "sysparm_query": f"sys_id={incident_sys_id}",
                "sysparm_fields": "sys_id,number,sys_created_on",
                "sysparm_limit": 1,
            }
            verify_response = make_servicenow_request(
                config=config,
                method="GET",
                endpoint=f"/table/{table_name}",
                params=verify_params,
            )
            verify_rows = verify_response.get("result", [])
            if verify_rows:
                verify_number = (verify_rows[0].get("number") or "").strip().upper()
                if verify_number != record_number:
                    response = {
                        "success": False,
                        "message": f"Sys_id verification failed: sys_id belongs to {verify_number}, not {record_number}",
                        "incident": None,
                    }
                    if input_label:
                        response[input_label] = record_number
                    return response
        except Exception as verify_e:
            logger.warning(f"Could not verify sys_id: {verify_e}")

        timeline_events: List[Dict[str, Any]] = []
        timeline_events_lock = threading.Lock()

        def fetch_work_notes():
            try:
                record_url = f"{config.api_url}/table/{table_name}/{incident_sys_id}"
                record_params = {
                    "sysparm_fields": "sys_id,number,work_notes",
                    "sysparm_display_value": "true",
                }
                response = requests.get(
                    record_url,
                    headers=get_auth_headers(config),
                    params=record_params,
                    timeout=config.timeout,
                )
                if response.status_code == 200:
                    result = response.json().get("result", {})
                    work_notes_text = result.get("work_notes", "")
                    if work_notes_text:
                        entries = parse_journal_field_text(work_notes_text, "work_note")
                        if entries:
                            with timeline_events_lock:
                                timeline_events.extend(entries)
                else:
                    logger.warning(f"work_notes fetch failed: HTTP {response.status_code}")
            except Exception as e:
                logger.warning(f"Failed to fetch work notes: {e}")

        def fetch_comments():
            try:
                record_url = f"{config.api_url}/table/{table_name}/{incident_sys_id}"
                record_params = {
                    "sysparm_fields": "sys_id,number,comments",
                    "sysparm_display_value": "true",
                }
                response = requests.get(
                    record_url,
                    headers=get_auth_headers(config),
                    params=record_params,
                    timeout=config.timeout,
                )
                if response.status_code == 200:
                    result = response.json().get("result", {})
                    comments_text = result.get("comments", "")
                    if comments_text:
                        entries = parse_journal_field_text(comments_text, "comment")
                        if entries:
                            with timeline_events_lock:
                                timeline_events.extend(entries)
                else:
                    logger.warning(f"comments fetch failed: HTTP {response.status_code}")
            except Exception as e:
                logger.warning(f"Failed to fetch comments: {e}")

        def fetch_audit_trail():
            try:
                audit_params = {
                    "sysparm_query": f"tablename={table_name}^documentkey={incident_sys_id}^fieldname=state",
                    "sysparm_order_by": "sys_created_on",
                    "sysparm_limit": 20,
                    "sysparm_display_value": "true",
                    "sysparm_fields": "sys_created_on,fieldname,oldvalue,newvalue,user",
                }
                audit_response = make_servicenow_request(
                    config=config,
                    method="GET",
                    endpoint="/table/sys_audit",
                    params=audit_params,
                    suppress_403=True,
                )
                audit_entries = audit_response.get("result", [])
                events = []
                for entry in audit_entries:
                    user = entry.get("user", {})
                    if isinstance(user, dict):
                        user = user.get("display_value", "Unknown")
                    else:
                        user = str(user) if user else "Unknown"

                    timestamp_str = entry.get("sys_created_on", "")
                    if timestamp_str:
                        try:
                            if "T" in timestamp_str:
                                dt = datetime.strptime(
                                    timestamp_str.split(".")[0].split("+")[0].split("Z")[0],
                                    "%Y-%m-%dT%H:%M:%S",
                                )
                                timestamp_str = dt.strftime("%m-%d-%Y %H:%M:%S")
                            elif len(timestamp_str) >= 19 and timestamp_str[4] == "-":
                                dt = datetime.strptime(timestamp_str[:19], "%Y-%m-%d %H:%M:%S")
                                timestamp_str = dt.strftime("%m-%d-%Y %H:%M:%S")
                        except Exception:
                            pass

                    events.append({
                        "timestamp": timestamp_str,
                        "type": "state_change",
                        "field": entry.get("fieldname", ""),
                        "old_value": entry.get("oldvalue", ""),
                        "new_value": entry.get("newvalue", ""),
                        "user": user,
                    })

                with timeline_events_lock:
                    timeline_events.extend(events)
            except Exception:
                pass

        threads = [
            threading.Thread(target=fetch_work_notes),
            threading.Thread(target=fetch_comments),
            threading.Thread(target=fetch_audit_trail),
        ]

        for thread in threads:
            thread.start()
        for thread in threads:
            thread.join()

        timeline_events.sort(key=lambda x: x.get("timestamp", ""))
        timeline_summary = _generate_timeline_summary(timeline_events, incident_data)

        state_map = {
            "1": "New",
            "2": "In Progress",
            "3": "On Hold",
            "4": "Resolved",
            "5": "Closed",
            "6": "Cancelled",
            "7": "Pending",
            "8": "Awaiting Information",
        }

        assignment_group = incident_data.get("assignment_group", "")
        if isinstance(assignment_group, dict):
            assignment_group = assignment_group.get("display_value", "Unassigned")
        elif not assignment_group:
            assignment_group = "Unassigned"

        assigned_to = incident_data.get("assigned_to", "")
        if isinstance(assigned_to, dict):
            assigned_to = assigned_to.get("display_value", "Unassigned")
        elif not assigned_to:
            assigned_to = "Unassigned"

        state = str(incident_data.get("state", ""))
        state_text = state_map.get(state, state)

        related_incidents: List[str] = []
        if (record_type == "case" or record_number.startswith("CS")) and incident_sys_id:
            related_incidents = _find_related_incidents_for_case(
                config=config,
                case_sys_id=incident_sys_id,
                case_number=record_number,
                case_record=incident_data,
            )

        incident_summary = {
            "number": incident_data.get("number", "N/A"),
            "sys_id": incident_sys_id,
            "record_type": record_type or ("case" if record_number.startswith("CS") else "incident"),
            "record_table": table_name or "unknown",
            "title": incident_data.get("short_description", "N/A"),
            "description": incident_data.get("description", "N/A"),
            "priority": incident_data.get("priority", "N/A"),
            "urgency": incident_data.get("urgency", "N/A"),
            "impact": incident_data.get("impact", "N/A"),
            "state": state,
            "state_text": state_text,
            "category": incident_data.get("category", "N/A"),
            "subcategory": incident_data.get("subcategory", "N/A"),
            "assignment_group": assignment_group,
            "assigned_to": assigned_to,
            "created_on": incident_data.get("sys_created_on", "N/A"),
            "updated_on": incident_data.get("sys_updated_on", "N/A"),
            "source_instance": incident_data.get("u_source_instance", "N/A"),
            "timeline": {
                "events": timeline_events,
                "summary": timeline_summary,
                "event_count": len(timeline_events),
            },
            "related_incidents": related_incidents,
            "related_incident_number": related_incidents[0] if related_incidents else None,
        }

        response = {
            "success": True,
            "message": f"Successfully retrieved {incident_summary['record_type']} {record_number}",
            "incident": incident_summary,
        }
        if input_label:
            response[input_label] = record_number
        return response

    except Exception as e:
        logger.error(f"Failed to get incident/case summary: {e}", exc_info=True)
        return {
            "success": False,
            "message": f"Failed to get incident/case summary: {str(e)}",
            "incident": None,
        }

